import{_ as e,c as t,o as i,a4 as a}from"./chunks/framework.BmdFiWrL.js";const k=JSON.parse('{"title":"Settings","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"en_US/guide/settings.md","filePath":"en_US/guide/settings.md","lastUpdated":1780234477000}'),s={name:"en_US/guide/settings.md"},n=a(`<h1 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h1><p><strong>After logging in to the admin page, click the avatar → System Settings to open the settings page.</strong></p><hr><h2 id="system-configuration" tabindex="-1">System Configuration <a class="header-anchor" href="#system-configuration" aria-label="Permalink to &quot;System Configuration&quot;">​</a></h2><h3 id="site-name" tabindex="-1">Site Name <a class="header-anchor" href="#site-name" aria-label="Permalink to &quot;Site Name&quot;">​</a></h3><p>Customize the site title here for easier identification and management.</p><h3 id="language-settings" tabindex="-1">Language Settings <a class="header-anchor" href="#language-settings" aria-label="Permalink to &quot;Language Settings&quot;">​</a></h3><p>Set the software language, mainly affecting notifications and error messages.</p><p>The web interface can also change language in real time.</p><h3 id="custom-code" tabindex="-1">Custom Code <a class="header-anchor" href="#custom-code" aria-label="Permalink to &quot;Custom Code&quot;">​</a></h3><p>This item is used to add custom styles or scripts to the web interface, such as changing the logo, background image, theme, external links, or analytics code.</p><p>The user frontend reads the following global variables. Set them in custom code with <code>&lt;script&gt;...&lt;/script&gt;</code>; use <code>true</code> / <code>false</code> for booleans, not strings.</p><ul><li><code>window.CustomBackgroundImage</code>: Desktop background image URL.</li><li><code>window.CustomMobileBackgroundImage</code>: Mobile background image URL. If unset, the desktop background image is used.</li><li><code>window.CustomLogo</code>: Logo image URL.</li><li><code>window.CustomDesc</code>: Homepage description text.</li><li><code>window.CustomLinks</code>: Custom external links. The value must be a JSON string parseable by <code>JSON.parse</code>, in the format <code>[{&quot;name&quot;:&quot;GitHub&quot;,&quot;link&quot;:&quot;https://github.com/nezhahq/nezha&quot;}]</code>.</li><li><code>window.ForceTheme</code>: Force the default color theme. Value is <code>&quot;light&quot;</code> or <code>&quot;dark&quot;</code>.</li><li><code>window.ShowNetTransfer</code>: Whether to show inbound/outbound traffic on server cards.</li><li><code>window.DisableAnimatedMan</code>: Whether to disable the default animated character illustration.</li><li><code>window.CustomIllustration</code>: Custom illustration URL. After setting it, it replaces the default illustration, and <code>window.DisableAnimatedMan</code> is usually unnecessary.</li><li><code>window.FixedTopServerName</code>: Whether to pin the top server name.</li><li><code>window.ForceUseSvgFlag</code>: Whether to force SVG flags.</li><li><code>window.ForceShowServices</code>: Whether to expand the homepage service monitoring panel by default.</li><li><code>window.ForceCardInline</code>: Whether to force the horizontal server list layout on non-mobile devices. Mobile devices still use the card layout.</li><li><code>window.ForceShowMap</code>: Whether to expand the homepage map by default.</li><li><code>window.ForcePeakCutEnabled</code>: Whether to enable network chart peak clipping by default, reducing the impact of sudden spikes on chart readability.</li></ul><p>Example:</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  window.CustomLogo </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://example.com/logo.png&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  window.CustomDesc </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;My Monitor&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  window.CustomLinks </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> JSON</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">stringify</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">([</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    { name: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;GitHub&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, link: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://github.com/nezhahq/nezha&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  window.ForceTheme </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;dark&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  window.ForceShowServices </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><ul><li>Admin frontend <ol><li><code>window.DisableAnimatedMan</code>: Boolean, turns the animated character illustration on/off.</li></ol></li></ul><h3 id="agent-connecting-address" tabindex="-1">Agent Connecting Address <a class="header-anchor" href="#agent-connecting-address" aria-label="Permalink to &quot;Agent Connecting Address&quot;">​</a></h3><ul><li>This is required when installing Agents with the one-click script.</li><li>Set it to the Agent connection address you want to use, for example: <code>data.example.com:8008</code>.</li><li>See <a href="/en_US/guide/agent.html#prerequisites">Agent Installation Prerequisites</a> for details.</li></ul><h3 id="reserved-dashboard-hosts" tabindex="-1">Reserved Dashboard Hosts <a class="header-anchor" href="#reserved-dashboard-hosts" aria-label="Permalink to &quot;Reserved Dashboard Hosts&quot;">​</a></h3><p>Declares the public hostnames used to access Dashboard, preventing normal members from creating NAT domains that collide with Dashboard entry hosts. Separate multiple hostnames with commas. The configuration field is <a href="/en_US/configuration/dashboard.html#reserved_hosts"><code>reserved_hosts</code></a>.</p><h3 id="custom-public-dns-nameservers-for-ddns" tabindex="-1">Custom Public DNS Nameservers for DDNS <a class="header-anchor" href="#custom-public-dns-nameservers-for-ddns" aria-label="Permalink to &quot;Custom Public DNS Nameservers for DDNS&quot;">​</a></h3><p>Used by DDNS to query domain SOA records. If empty, the built-in list is used.</p><h3 id="frontend-real-ip-request-header" tabindex="-1">Frontend Real IP Request Header <a class="header-anchor" href="#frontend-real-ip-request-header" aria-label="Permalink to &quot;Frontend Real IP Request Header&quot;">​</a></h3><ul><li><code>CF-Connecting-IP</code> is a request header used to get the visitor&#39;s real IP.</li><li>When accessing the Dashboard through Cloudflare CDN proxy, enabling this feature lets the origin server identify the visitor&#39;s real IP correctly. <ul><li><strong>Use</strong>: Security auditing, firewall rules, and logging.</li></ul></li></ul><div class="danger custom-block"><p class="custom-block-title">DANGER</p><ol><li><p><strong>Configure Headers Carefully</strong> Frontend real IP request header configuration affects the built-in WAF (Web Application Firewall). If you do not understand how headers are passed, do not modify this casually. Incorrect configuration may cause IPs to be blocked by the built-in WAF.</p></li><li><p><strong>Prevent Account Brute Force Attacks</strong> The built-in WAF is designed to prevent local account brute force.</p><ul><li>If local accounts have no protection, high-frequency password enumeration attacks may occur, such as 100 password attempts per second.</li><li>WAF IP identification depends on correctly configured request headers to block such attacks effectively.</li></ul></li><li><p><strong>Security Advice</strong> Enable this only after you understand how headers are actually passed, and carefully verify the result.</p></li></ol></div><h3 id="agent-real-ip-request-header" tabindex="-1">Agent Real IP Request Header <a class="header-anchor" href="#agent-real-ip-request-header" aria-label="Permalink to &quot;Agent Real IP Request Header&quot;">​</a></h3><ul><li><code>CF-Connecting-IP</code> is a request header used to get the Agent&#39;s real IP.</li><li>When Agents connect to the Dashboard through Cloudflare CDN proxy, enabling this feature lets the origin server identify the Agent&#39;s real IP correctly.</li></ul><h3 id="mcp-toggle" tabindex="-1">MCP Toggle <a class="header-anchor" href="#mcp-toggle" aria-label="Permalink to &quot;MCP Toggle&quot;">​</a></h3><p>Enables or disables the Dashboard MCP endpoint. After enabling it, clients can call <code>POST /mcp</code> with a PAT. When disabled, Dashboard rejects new MCP requests and interrupts related transfers. The configuration field is <a href="/en_US/configuration/dashboard.html#enable_mcp"><code>enable_mcp</code></a>. For authentication and permission details, see <a href="/en_US/guide/api.html#mcp-access">API Interface - MCP Access</a>.</p><h3 id="ip-change-notification" tabindex="-1">IP Change Notification <a class="header-anchor" href="#ip-change-notification" aria-label="Permalink to &quot;IP Change Notification&quot;">​</a></h3><p>This feature sends notifications when a server IP address changes. Configure it as follows:</p><h4 id="configuration-options" tabindex="-1">Configuration Options <a class="header-anchor" href="#configuration-options" aria-label="Permalink to &quot;Configuration Options&quot;">​</a></h4><ol><li><p><strong>Cover</strong> Select a rule to determine which servers need monitoring.</p></li><li><p><strong>Specific Servers</strong> Used together with Cover to add exclusions for the selected rule.</p></li><li><p><strong>Send notification to notification group</strong> Select notification methods. Notification methods must be configured in advance on the Notifications page.</p></li><li><p><strong>Enable</strong> After configuration, check <strong>Enable</strong> to make notifications take effect.</p></li><li><p><strong>Show full IP address in notification</strong> By default, IP change notifications hide the full IP address. Check this option if you need to show the complete IP address.</p></li></ol><hr><h2 id="api-tokens" tabindex="-1">API Tokens <a class="header-anchor" href="#api-tokens" aria-label="Permalink to &quot;API Tokens&quot;">​</a></h2><p>This tab creates and revokes Personal Access Tokens (PATs). PATs are suitable for automation scripts, CI, LLM tools, and MCP clients.</p><p>When creating a token, select scopes, optional server ID whitelist, and expiration. The plaintext token is shown only once after creation. Later lists only show metadata such as scopes, server whitelist, expiration time, last used time, and last used IP. For authentication format and scopes, see <a href="/en_US/guide/api.html#personal-access-token-pat">API Interface - Personal Access Token</a>.</p><hr><h2 id="user-management" tabindex="-1">User Management <a class="header-anchor" href="#user-management" aria-label="Permalink to &quot;User Management&quot;">​</a></h2><p>This tab allows adding multiple users to the Dashboard.</p><p>See <a href="/en_US/guide/user.html">Multi-User</a> for details.</p><hr><h2 id="online-users" tabindex="-1">Online Users <a class="header-anchor" href="#online-users" aria-label="Permalink to &quot;Online Users&quot;">​</a></h2><p>View current guests / users connected to the frontend, including <strong>IP</strong> and <strong>connection time</strong>, and manually block users. Administrators can also batch block selected online users.</p><hr><h2 id="web-application-firewall" tabindex="-1">Web Application Firewall <a class="header-anchor" href="#web-application-firewall" aria-label="Permalink to &quot;Web Application Firewall&quot;">​</a></h2><p>You can view current block entries and related useful information:</p><ul><li><strong>IP</strong>: The blocked user&#39;s IP.</li><li><strong>Block ID</strong>: The resource identifier the blocked user attempted to attack. Together with IP, it identifies a block entry. Usually this is a user ID, but there are these special cases: <ol><li>Attempting to brute force a gRPC connection secret;</li><li>Attempting to brute force an API Token;</li><li>Attempting to log in to a nonexistent user;</li><li>Manual block through the Online Users page.</li></ol></li><li><strong>Count</strong>: Number of times this entry has been blocked. Higher counts result in longer block times.</li><li><strong>Reason</strong>: The reason for the latest block on this entry.</li><li><strong>Time</strong>: The latest block time for this entry.</li></ul><p>If the current user is an administrator, block entries can be deleted manually or in batches.</p>`,49),o=[n];function r(l,h,d,c,u,p){return i(),t("div",null,o)}const m=e(s,[["render",r]]);export{k as __pageData,m as default};
